private fun ASTNode.calculateIndentOfFunctionLiteralParameters() =
    // Only apply alignment for lambdas with explicit parameter lists
    val hasExplicitParameterList =
        parent(FUNCTION_LITERAL)?.findChildByType(VALUE_PARAMETER_LIST) != null

    if (!hasExplicitParameterList || codeStyle == ktlint_official || isFirstParameterOfFunctionLiteralPrecededByNewLine()) {
        // val fieldExample =
        //      LongNameClass {
        //              paramA,
        //              paramB,
        //              paramC ->
        //          ClassB(paramA, paramB, paramC)
        //      }
        // For lambdas with implicit single parameter (e.g. { it }),
        // or ktlint_official style, use standard indentation
        indentConfig.indent.repeat(2)
    } else {
        // Allow default IntelliJ IDEA formatting:
        // val fieldExample =
        //     LongNameClass { paramA,
        //                     paramB,
        //                     paramC ->
        //         ClassB(paramA, paramB, paramC)
        //     }
        parent(CALL_EXPRESSION)
            ?.let { callExpression ->
                val textBeforeFirstParameter =
                    callExpression.findChildByType(REFERENCE_EXPRESSION)?.text +
                        " { "
                " ".repeat(textBeforeFirstParameter.length)
            }
            ?: indentConfig.indent.repeat(2)
    }

